package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.ByteArrayInputStream;
import java.io.IOException;
import java.io.InputStream;
import java.nio.charset.StandardCharsets;

import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class CSVParserParseTest {

    @Test
    void parse_withValidInputStreamAndCharsetAndFormat_returnsCSVParser() throws IOException {
        // Arrange
        String csvContent = "header1,header2\nvalue1,value2";
        InputStream inputStream = new ByteArrayInputStream(csvContent.getBytes(StandardCharsets.UTF_8));
        CSVFormat format = mock(CSVFormat.class);

        // Mock Assertions.notNull to do nothing (assuming it's a static utility method)
        try (MockedStatic<Assertions> mockedAssertions = Mockito.mockStatic(Assertions.class)) {
            mockedAssertions.when(() -> Assertions.notNull(any(), anyString())).thenAnswer(invocation -> null);

            // Mock CSVParser.parse(Reader, CSVFormat) static method to verify delegation
            try (MockedStatic<CSVParser> mockedCSVParser = Mockito.mockStatic(CSVParser.class, Mockito.CALLS_REAL_METHODS)) {
                // We want to call the real method under test, so delegate parse(InputStream, Charset, CSVFormat)
                // but mock parse(Reader, CSVFormat) to return a dummy CSVParser
                CSVParser dummyParser = mock(CSVParser.class);
                mockedCSVParser.when(() -> CSVParser.parse(any(java.io.Reader.class), eq(format))).thenReturn(dummyParser);

                // Act
                CSVParser result = CSVParser.parse(inputStream, StandardCharsets.UTF_8, format);

                // Assert
                assertNotNull(result);
                assertSame(dummyParser, result);

                // Verify that Assertions.notNull was called for inputStream and format
                mockedAssertions.verify(() -> Assertions.notNull(inputStream, "inputStream"));
                mockedAssertions.verify(() -> Assertions.notNull(format, "format"));

                // Verify that parse(Reader, CSVFormat) was called once
                mockedCSVParser.verify(() -> CSVParser.parse(any(java.io.Reader.class), eq(format)));
            }
        }
    }

    @Test
    void parse_withNullInputStream_throwsNullPointerException() {
        CSVFormat format = mock(CSVFormat.class);

        try (MockedStatic<Assertions> mockedAssertions = Mockito.mockStatic(Assertions.class)) {
            mockedAssertions.when(() -> Assertions.notNull(null, "inputStream")).thenThrow(new NullPointerException("inputStream"));

            NullPointerException ex = assertThrows(NullPointerException.class, () -> CSVParser.parse(null, StandardCharsets.UTF_8, format));
            assertEquals("inputStream", ex.getMessage());

            mockedAssertions.verify(() -> Assertions.notNull(null, "inputStream"));
        }
    }

    @Test
    void parse_withNullFormat_throwsNullPointerException() {
        InputStream inputStream = new ByteArrayInputStream("data".getBytes(StandardCharsets.UTF_8));

        try (MockedStatic<Assertions> mockedAssertions = Mockito.mockStatic(Assertions.class)) {
            mockedAssertions.when(() -> Assertions.notNull(inputStream, "inputStream")).thenReturn(null);
            mockedAssertions.when(() -> Assertions.notNull(null, "format")).thenThrow(new NullPointerException("format"));

            NullPointerException ex = assertThrows(NullPointerException.class, () -> CSVParser.parse(inputStream, StandardCharsets.UTF_8, null));
            assertEquals("format", ex.getMessage());

            mockedAssertions.verify(() -> Assertions.notNull(inputStream, "inputStream"));
            mockedAssertions.verify(() -> Assertions.notNull(null, "format"));
        }
    }
}
